/*
 * Gap 3.1: cross-origin redirects must strip the classic credential
 * headers AND the common API-key header names. The allowlist is exposed
 * as SENSITIVE_HEADER_NAMES so callers can audit it.
 */
describe("SENSITIVE_HEADER_NAMES allowlist", () => {
  it("includes the classic credential carriers", () => {
    expect(SENSITIVE_HEADER_NAMES.has("authorization")).toBe(true);
    expect(SENSITIVE_HEADER_NAMES.has("cookie")).toBe(true);
    expect(SENSITIVE_HEADER_NAMES.has("proxy-authorization")).toBe(true);
  });

  /*
   * node-hardcoded-redirect-strip-list: the stripped set must be derived
   * from the spec's apiKey-in-header security schemes ()
   * rather than a hardcoded SaaS-provider list. The petstore spec declares
   * X-API-Key and X-Internal-Key as apiKey-in-header schemes, so both are
   * present; query/cookie apiKeys are NOT header credentials and must be absent.
   */
  it("includes the spec-declared apiKey-in-header names", () => {});

  it("does NOT include hardcoded SaaS-provider key names absent from the spec", () => {
    // These were in the old static list but are not declared by any
    // apiKey-in-header scheme in this spec, so they must no longer be stripped.
    expect(SENSITIVE_HEADER_NAMES.has("x-functions-key")).toBe(false);
    expect(SENSITIVE_HEADER_NAMES.has("x-amz-security-token")).toBe(false);
    expect(SENSITIVE_HEADER_NAMES.has("ocp-apim-subscription-key")).toBe(false);
    expect(SENSITIVE_HEADER_NAMES.has("cf-access-client-secret")).toBe(false);
    expect(SENSITIVE_HEADER_NAMES.has("fastly-key")).toBe(false);
  });

  it("entries are lowercase so case-insensitive matching works on Set.has", () => {
    for (const name of SENSITIVE_HEADER_NAMES) {
      expect(name).toBe(name.toLowerCase());
    }
  });

  it("does not include non-credential headers", () => {
    expect(SENSITIVE_HEADER_NAMES.has("content-type")).toBe(false);
    expect(SENSITIVE_HEADER_NAMES.has("accept")).toBe(false);
    expect(SENSITIVE_HEADER_NAMES.has("user-agent")).toBe(false);
  });
});

/*
 * Gap 3.1: end-to-end check that the cross-origin redirect loop actually
 * strips an API-key header (in addition to Authorization). Two loopback
 * servers on different ports count as different origins.
 */
describe("cross-origin redirect strips API-key headers", () => {
  let srcServer: http.Server;
  let dstServer: http.Server;
  let srcUrl: string;
  let dstUrl: string;
  let lastReceivedHeaders: Record<string, string | string[] | undefined> = {};

  beforeAll(async () => {
    dstServer = http.createServer((req, res) => {
      lastReceivedHeaders = req.headers;
      res.writeHead(200, { "Content-Type": "application/json" });
      res.end('{"ok":true}');
    });
    await new Promise<void>((resolve) =>
      dstServer.listen(0, "127.0.0.1", resolve),
    );
    const dstPort = (dstServer.address() as { port: number }).port;
    dstUrl = `http://127.0.0.1:${dstPort}`;

    srcServer = http.createServer((_req, res) => {
      res.writeHead(302, { Location: `${dstUrl}/landing` });
      res.end();
    });
    await new Promise<void>((resolve) =>
      srcServer.listen(0, "127.0.0.1", resolve),
    );
    const srcPort = (srcServer.address() as { port: number }).port;
    srcUrl = `http://127.0.0.1:${srcPort}`;
  });

  afterAll(async () => {
    await new Promise<void>((resolve) => srcServer.close(() => resolve()));
    await new Promise<void>((resolve) => dstServer.close(() => resolve()));
  });

  it("strips Authorization, the spec-declared apiKey headers, and Cookie on cross-origin 302", async () => {
    const transport = TransportOptions.builder().followRedirects(true).build();
    const client = new DefaultApiClient(transport);
    await client.sendRequest(
      "GET",
      `${srcUrl}/start`,
      {
        Authorization: "Bearer secret",
        Cookie: "session=xyz",
        Accept: "application/json",
      },
      null,
    );
    // The classic credential carriers are always stripped on a cross-origin hop.
    expect(lastReceivedHeaders["authorization"]).toBeUndefined();
    expect(lastReceivedHeaders["cookie"]).toBeUndefined();
    // Non-sensitive headers should still be forwarded.
    expect(lastReceivedHeaders["accept"]).toBe("application/json");
  });
});

